package scheduler

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/scheduler"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type SchedulerHandlerProxy struct {
	scheduler.UnimplementedSchedulerHandlerServer
	client scheduler.SchedulerHandlerClient
}

func init() {
	proxyutil.Register(&scheduler.SchedulerHandler_ServiceDesc, NewSchedulerHandlerProxy)
}
func NewSchedulerHandlerProxy(cc grpc.ClientConnInterface) scheduler.SchedulerHandlerServer {
	return &SchedulerHandlerProxy{client: scheduler.NewSchedulerHandlerClient(cc)}
}
func (p *SchedulerHandlerProxy) HandleScheduledAction(ctx context.Context, in *scheduler.ScheduledAction) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[scheduler.ScheduledAction, emptypb.Empty](p.client.HandleScheduledAction)(ctx, in)
}
